// Create from an array (duplicates are removed)
const set = new Set([1, 2, 3, 2, 1]);
console.log(set); // Set(3) { 1, 2, 3 }

// Create empty and add values
const tags = new Set();
tags.add('react');
tags.add('javascript');
tags.add('react'); // ignored — already exists
console.log(tags.size); // 2

// Check existence
tags.has('react');      // true
tags.has('python');     // false

// Remove a value
tags.delete('react');
console.log(tags.has('react')); // false

// Clear all
tags.clear();

const fruits = new Set(['apple', 'banana', 'cherry']);

// for...of
for (const fruit of fruits) {
  console.log(fruit);
}

// forEach
fruits.forEach(fruit => console.log(fruit));

// Convert to array (for array methods like map/filter)
const arr = [...fruits];
const arr2 = Array.from(fruits);

// Remove duplicates from an array in one line
const withDupes = [3, 1, 4, 1, 5, 9, 2, 6, 5, 3];
const unique = [...new Set(withDupes)];
console.log(unique); // [3, 1, 4, 5, 9, 2, 6]

// Remove duplicate strings:
const tags = ['react', 'hooks', 'react', 'state'];
const uniqueTags = [...new Set(tags)];
console.log(uniqueTags); // ['react', 'hooks', 'state']

// Create empty
const map = new Map();

// Set key-value pairs
map.set('name', 'Alice');
map.set('age', 28);
map.set(42, 'the answer');     // number key
map.set(true, 'boolean key'); // boolean key

// Get values
map.get('name');  // 'Alice'
map.get(42);      // 'the answer'
map.get('missing'); // undefined

// Check existence
map.has('name'); // true
map.has('foo');  // false

// Size
map.size; // 4

// Delete
map.delete('age');

// Create from array of [key, value] pairs
const userMap = new Map([
  ['u1', { name: 'Alice' }],
  ['u2', { name: 'Bob' }],
]);

const scores = new Map([['Alice', 95], ['Bob', 82], ['Carol', 91]]);

// Iterate entries
for (const [name, score] of scores) {
  console.log(`${name}: ${score}`);
}

// Keys and values separately
[...scores.keys()];   // ['Alice', 'Bob', 'Carol']
[...scores.values()]; // [95, 82, 91]
[...scores.entries()]; // [['Alice', 95], ...]

// Convert to array of objects
const arr = [...scores].map(([name, score]) => ({ name, score }));

import { useState } from 'react';

function MultiSelect({ items }) {
  const [selected, setSelected] = useState(new Set());

  function toggle(id) {
    setSelected(prev => {
      const next = new Set(prev); // create a new Set (immutable update)
      if (next.has(id)) {
        next.delete(id);
      } else {
        next.add(id);
      }
      return next;
    });
  }

  return (
    <ul>
      {items.map(item => (
        <li key={item.id} onClick={() => toggle(item.id)}>
          {selected.has(item.id) ? '✓ ' : '  '}
          {item.name}
        </li>
      ))}
    </ul>
  );
}

import { useState, useEffect } from 'react';

function App() {
  const [userMap, setUserMap] = useState(new Map());

  useEffect(() => {
    fetch('/api/users')
      .then(r => r.json())
      .then(users => {
        // Build a Map for O(1) lookups
        const map = new Map(users.map(u => [u.id, u]));
        setUserMap(map);
      });
  }, []);

  // Later: userMap.get(id) is O(1) — no array.find() needed
  return <Dashboard getUserById={id => userMap.get(id)} />;
}

function TagCloud({ posts }) {
  // Collect all tags, removing duplicates with Set
  const allTags = [...new Set(posts.flatMap(post => post.tags))].sort();

  return (
    <div>
      {allTags.map(tag => (
        <span key={tag} className="tag">{tag}</span>
      ))}
    </div>
  );
}
